import React from "react";
import { Link, useNavigate } from "react-router-dom";

function Sidebar({ role = "patient" }) {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user"));

  const logout = () => {
    localStorage.removeItem("user");
    localStorage.removeItem("prediction_result");
    navigate("/login");
  };

  return (
    <div className="sidebar">
      <div>
        <h2 className="sidebar-logo">AI Doctor</h2>
        <p className="sidebar-role">
          {role === "admin" ? "Admin Panel" : "Patient Panel"}
        </p>

        <div className="sidebar-links">
          {role === "patient" && (
            <>
              <Link to="/prediction">Prediction</Link>
              <Link to="/result">Result</Link>
              <Link to="/history">Prediction History</Link>
              <Link to="/appointments">Appointments</Link>
            </>
          )}

          {role === "admin" && (
            <>
              <Link to="/reports">Reports</Link>
              <Link to="/doctors">Doctors</Link>
              <Link to="/appointments">Appointments</Link>
            </>
          )}
        </div>
      </div>

      <div className="sidebar-footer">
        <p className="mb-2">{user?.name || "User"}</p>
        <button className="btn btn-sm btn-light w-100" onClick={logout}>
          Logout
        </button>
      </div>
    </div>
  );
}

export default Sidebar;
